  ('dietitian-moex-01422', 'dietitian', 'dietitian-moex-109-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '學校午餐由委外廠商供應，菜單內容有：地瓜飯、糖醋素肉排、炒三色豆（豌豆仁、玉米粒、胡 蘿蔔）、蒜香菠菜、蘿蔔貢丸湯、香蕉。為兼顧低碳飲食原則與學童營養需求，學校營養師審查', '["將糖醋素肉排改為紅燒豆腐", "蘿蔔貢丸湯改為番茄蛋花湯", "炒三色豆的豌豆仁改為毛豆", "香蕉改為柳橙汁 ⑤地瓜飯撒些黑芝麻 ⑥為成長階段學生 熱量所需，額外提供麵包"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "73a0704b25f2", "answer_pdf_sha1": "a8a9e9767cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
